        "# ABC INVENTORY CLASSIFICATION\n",
        "abc = product_sales.reset_index()\n",
        "abc.columns = ['Product_Name', 'Revenue']\n",
        "\n",
        "abc['Revenue_Percentage'] = abc['Revenue'] / abc['Revenue'].sum()\n",
        "abc['Cumulative_Percentage'] = abc['Revenue_Percentage'].cumsum()\n",
        "\n",
        "# ABC Logic\n",
        "abc['Category'] = 'C'\n",
        "abc.loc[abc['Cumulative_Percentage'] <= 0.80, 'Category'] = 'A'\n",
        "abc.loc[(abc['Cumulative_Percentage'] > 0.80) & (abc['Cumulative_Percentage'] <= 0.95), 'Category'] = 'B'\n",
        "\n",
        "print('\\n===== ABC INVENTORY CLASSIFICATION =====')\n",
        "print(abc)\n",
        "\n",
        "# ABC Classification\n",
        "plt.figure(figsize=(10,6))\n",
        "plt.bar(abc['Product_Name'], abc['Revenue'])\n",
        "plt.title('ABC Inventory Classification')\n",
        "plt.xlabel('Product')\n",
        "plt.ylabel('Revenue')\n",
        "plt.xticks(rotation=90)\n",
        "plt.tight_layout()\n",
        "plt.show()"
