        "# SALES FORECAST (3-Month MA + Linear Trend)\n",
        "import numpy as np\n",
        "from sklearn.linear_model import LinearRegression\n",
        "import matplotlib.pyplot as plt\n",
        "import matplotlib.ticker as mticker\n",
        "import pandas as pd\n",
        "\n",
        "print(\"\\n===== SALES FORECAST =====\")\n",
        "monthly[\"month_num\"] = range(1, len(monthly) + 1)\n",
        "monthly[\"ma3\"]       = monthly[\"Revenue\"].rolling(3).mean()\n",
        "\n",
        "X   = monthly[[\"month_num\"]].values\n",
        "y   = monthly[\"Revenue\"].values\n",
        "reg = LinearRegression().fit(X, y)\n",
        "monthly[\"trend\"] = reg.predict(X)\n",
        "\n",
        "future_nums   = np.array([[len(monthly)+i] for i in range(1, 4)])\n",
        "future_labels = [\"2025-01\",\"2025-02\",\"2025-03\"]\n",
        "future_ma3    = [monthly[\"Revenue\"].iloc[-3:].mean()] * 3\n",
        "future_trend  = reg.predict(future_nums)\n",
        "\n",
        "forecast_df = pd.DataFrame({\n",
        "    \"month_str\"     : future_labels,\n",
        "    \"Revenue\"       : [None]*3,\n",
        "    \"ma3\"           : future_ma3,\n",
        "    \"trend\"         : future_trend,\n",
        "    \"month_num\"     : future_nums.flatten(),\n",
        "})\n",
        "forecast_combined = pd.concat(\n",
        "    [monthly[[\"month_str\",\"Revenue\",\"ma3\",\"trend\",\"month_num\"]], forecast_df],\n",
        "    ignore_index=True\n",
        ")\n",
        "\n",
        "print(\"\\n----- Last 3 Actual + Next 3 Forecast -----\")\n",
        "print(forecast_combined.tail(6)[[\"month_str\",\"Revenue\",\"ma3\",\"trend\"]].to_string(index=False))\n",
        "\n",
        "fig, ax = plt.subplots(figsize=(13, 5))\n",
        "ax.plot(forecast_combined[\"month_str\"], forecast_combined[\"Revenue\"],\n",
        "        marker=\"o\", color=\"#1E2761\", linewidth=2.2, label=\"Actual Revenue\")\n",
        "ax.plot(forecast_combined[\"month_str\"], forecast_combined[\"ma3\"],\n",
        "        marker=\"s\", linestyle=\"--\", color=\"#1D9E75\", linewidth=1.8, label=\"3-Month MA Forecast\")\n",
        "ax.plot(forecast_combined[\"month_str\"], forecast_combined[\"trend\"],\n",
        "        linestyle=\":\", color=\"#D85A30\", linewidth=1.8, label=\"Linear Trend\")\n",
        "ax.axvline(x=\"2024-12\", color=\"gray\", linestyle=\"--\", alpha=0.5, label=\"Forecast Start\")\n",
        "ax.set_title(\"Revenue Forecast — 2024 Actual + Q1 2025 Projection\", fontweight=\"bold\")\n",
        "ax.set_ylabel(\"Revenue (฿)\")\n",
        "ax.yaxis.set_major_formatter(mticker.FuncFormatter(lambda x,_: f\"฿{x/1e6:.1f}M\"))\n",
        "ax.tick_params(axis=\"x\", rotation=45)\n",
        "ax.legend()\n",
        "ax.grid(True, alpha=0.3)\n",
        "plt.tight_layout()\n",
        "plt.show()"
